// // This module decrements a 3-bit binary counter on each positive clock edge when the enable signal is high and sets it to 7 when the clear input is active.
module top_module (
  input clk,
  input enable,
  input clear,
  output reg [2:0] q);always @(posedge clk) begin
		if (clear)
			q <= 3'b000;
		else if (enable)
			q <= q + 1;
	end
endmodule
